Функция ПолучитьДебетовыйОборотПоКонтрагенту(СсылкаНаСчет, СсылкаНаКонтрагента) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ
        |    Регистратор.Сумма КАК Оборот
        |ИЗ
        |    РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто КАК ДвиженияССубконто
        |ГДЕ
        |    ДвиженияССубконто.СчетДт = &СсылкаНаСчет
        |    И (ДвиженияССубконто.СубконтоДт1 = &СсылкаНаКонтрагента
        |       ИЛИ ДвиженияССубконто.СубконтоДт2 = &СсылкаНаКонтрагента)";

    Запрос.УстановитьПараметр("СсылкаНаСчет", СсылкаНаСчет);
    Запрос.УстановитьПараметр("СсылкаНаКонтрагента", СсылкаНаКонтрагента);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();

    Если Выборка.Следующий() Тогда
        Возврат Выборка.Оборот;
    Иначе
        Возврат 0;
    КонецЕсли;
КонецФункции
